content.content:
1	/**
2	 * Collection Report Page Content Component
3	 *
4	 * Main content component that orchestrates all data fetching, state management,
5	 * and renders the collection report management interface.
6	 *
7	 * Features:
8	 * - Multi-tab interface (Collection, Monthly, Collector Schedule, Manager Schedule)
9	 * - Animated tab transitions
10	 * - Responsive layout management
11	 * - Centralized modal management
12	 * - Role-based access control for tab visibility
13	 */
14	
15	'use client';
16	
17	import { FC, useCallback, useEffect, useRef, useState } from 'react';
18	import dynamic from 'next/dynamic';
19	import { useRouter, useSearchParams } from 'next/navigation';
20	import { AnimatePresence, motion } from 'framer-motion';
21	import axios from 'axios';
22	
23	// === Internal Components ===
24	import CollectionReportHeader from '@/components/CMS/collectionReport/CollectionReportHeader';
25	import CollectionReportNavigation from '@/components/CMS/collectionReport/CollectionReportNavigation';
26	import CollectionReportModals from '@/components/CMS/collectionReport/modals/CollectionReportModals';
27	import ScheduleDeleteDialog from '@/components/CMS/collectionReport/modals/ScheduleDeleteDialog';
28	import ScheduleEditModal from '@/components/CMS/collectionReport/modals/ScheduleEditModal';
29	import CollectionReportDesktopLayout from '@/components/CMS/collectionReport/tabs/collection/CollectionReportDesktopLayout';
30	import CollectionReportMobileLayout from '@/components/CMS/collectionReport/tabs/collection/CollectionReportMobileLayout';
31	import CollectionReportV2Desktop from '@/components/CMS/collectionReport/tabs/collection-v2/CollectionReportV2Desktop';
32	import CollectionReportV2Mobile from '@/components/CMS/collectionReport/tabs/collection-v2/CollectionReportV2Mobile';
33	import CollectionReportV2Filters from '@/components/CMS/collectionReport/tabs/collection-v2/CollectionReportV2Filters';
34	import CollectionReportV2StartSessionDialog from '@/components/CMS/collectionReport/tabs/collection-v2/CollectionReportV2StartSessionDialog';
35	import CollectionReportV2DeleteSessionModal from '@/components/CMS/collectionReport/modals/CollectionReportV2DeleteSessionModal';
36	import CollectionReportV2EditSessionModal from '@/components/CMS/collectionReport/modals/CollectionReportV2EditSessionModal';
37	import CollectionReportV2WizardModal from '@/components/CMS/collectionReport/modals/CollectionReportV2WizardModal';
38	
39	// === Shared Components ===
40	import PageLayout from '@/components/shared/layout/PageLayout';
41	import DateFilters from '@/components/shared/ui/common/DateFilters';
42	import { NoLicenceeAssigned } from '@/components/shared/ui/NoLicenceeAssigned';
43	import PaginationControls from '@/components/shared/ui/PaginationControls';
44	
45	// === Hooks & Store ===
46	import { COLLECTION_TABS_CONFIG, UserRole } from '@/lib/constants';
47	import { useCollectionReportPageData } from '@/lib/hooks/collectionReport/useCollectionReportPageData';
48	import { useCollectionReportV2Data } from '@/lib/hooks/collectionReport/useCollectionReportV2Data';
49	import { useCollectorScheduleData } from '@/lib/hooks/collectionReport/useCollectorScheduleData';
50	import { useManagerScheduleData } from '@/lib/hooks/collectionReport/useManagerScheduleData';
51	import { useMonthlyReportData } from '@/lib/hooks/collectionReport/useMonthlyReportData';
52	import { useDashBoardStore } from '@/lib/store/dashboardStore';
53	import { useUserStore } from '@/lib/store/userStore';
54	
55	// === Utilities ===
56	import {
57	  shouldShowLicenceeFilter,
58	  shouldShowNoLicenceeMessage,
59	} from '@/lib/utils/licencee';
60	import { hasManagerAccess } from '@/lib/utils/permissions';
61	
62	// === Specialized Tab UI Components (Dynamically Imported) ===
63	const MonthlyDesktop = dynamic(
64	  () =>
65	    import('@/components/CMS/collectionReport/tabs/monthly/CollectionReportMonthlyDesktop'),
66	  { ssr: false }
67	);
68	const MonthlyMobile = dynamic(
69	  () =>
70	    import('@/components/CMS/collectionReport/tabs/monthly/CollectionReportMonthlyMobile'),
71	  { ssr: false }
72	);
73	const CollectorDesktop = dynamic(
74	  () =>
75	    import('@/components/CMS/collectionReport/tabs/collector/CollectionReportCollectorDesktop'),
76	  { ssr: false }
77	);
78	const CollectorMobile = dynamic(
79	  () =>
80	    import('@/components/CMS/collectionReport/tabs/collector/CollectionReportCollectorMobile'),
81	  { ssr: false }
82	);
83	const ManagerDesktop = dynamic(
84	  () =>
85	    import('@/components/CMS/collectionReport/tabs/manager/CollectionReportManagerDesktop'),
86	  { ssr: false }
87	);
88	const ManagerMobile = dynamic(
89	  () =>
90	    import('@/components/CMS/collectionReport/tabs/manager/CollectionReportManagerMobile'),
91	  { ssr: false }
92	);
93	
94	const MotionDiv = motion.div;
95	
96	const CollectionReportPageContent: FC = () => {
97	  // ============================================================================
98	  // State & Hooks
99	  // ============================================================================
100	  const hook = useCollectionReportPageData();
101	  const { user } = useUserStore();
102	  const { setSelectedLicencee, selectedLicencee } = useDashBoardStore();
103	
104	  const desktopTableRef = useRef<HTMLDivElement | null>(null);
105	  const mobileCardsRef = useRef<HTMLDivElement | null>(null);
106	  const [isSearching, setIsSearching] = useState(false);
107	  const [showV2StartSession, setShowV2StartSession] = useState(false);
108	  const [v2DeleteConfirm, setV2DeleteConfirm] = useState<string | null>(null);
109	  const [v2EditSessionId, setV2EditSessionId] = useState<string | null>(null);
110	  const [v2WizardSessionId, setV2WizardSessionId] = useState<string | null>(
111	    null
112	  );
113	  const v2SessionsRef = useRef<{ sessionId: string; deletedAt?: unknown }[]>(
114	    []
115	  );
116	
117	  const router = useRouter();
118	  const searchParams = useSearchParams();
119	
120	  // ============================================================================
121	  // Effects
122	  // ============================================================================
123	  // On mount + whenever the URL changes, mirror ?view= into local state.
124	  useEffect(() => {
125	    const viewParam = searchParams?.get('view') ?? null;
126	    setV2EditSessionId(prev => (prev === viewParam ? prev : viewParam));
127	  }, [searchParams]);
128	
129	  // ============================================================================
130	  // Handlers
131	  // ============================================================================
132	  // Open a session in view-mode AND push the URL so it's shareable.
133	  const openV2View = useCallback(
134	    (sessionId: string) => {
135	      setV2EditSessionId(sessionId);
136	      const params = new URLSearchParams(searchParams?.toString() || '');
137	      params.set('view', sessionId);
138	      router.push(`/collection-report?${params.toString()}`, { scroll: false });
139	    },
140	    [router, searchParams]
141	  );
142	
143	  // Close the view modal AND strip ?view= from the URL.
144	  const closeV2View = useCallback(() => {
145	    setV2EditSessionId(null);
146	    const params = new URLSearchParams(searchParams?.toString() || '');
147	    params.delete('view');
148	    const query = params.toString();
149	    router.push(query ? `/collection-report?${query}` : '/collection-report', {
150	      scroll: false,
151	    });
152	  }, [router, searchParams]);
153	
154	  // ============================================================================
155	  // Computed & Additional Hooks
156	  // ============================================================================
157	  // Destructure hook for better readability
158	  const {
159	    activeTab,
160	    loading,
161	    refreshing,
162	    allReports,
163	    locations,
164	    locationsWithMachines,
165	    showNewCollectionMobile,
166	    showNewCollectionDesktop,
167	    showEditMobile,
168	    showEditDesktop,
169	    editingReportId,
170	    showDeleteConfirmation,
171	    filters,
172	    handleTabChange,
173	    handleRefresh,
174	    handleCreate,
175	    handleEdit,
176	    handleDelete,
177	    confirmDelete,
178	    setSearchTerm,
179	    setCurrentPage,
180	    setShowNewCollectionMobile,
181	    setShowNewCollectionDesktop,
182	    setShowEditMobile,
183	    setShowEditDesktop,
184	    setEditingReportId,
185	    onRefreshLocations,
186	    currentDeletePhase,
187	  } = hook;
188	
189	  // Initialize specialized hooks for secondary tabs
190	  const monthlyHook = useMonthlyReportData(selectedLicencee, activeTab);
191	  const collectorHook = useCollectorScheduleData(selectedLicencee, locations);
192	  const managerHook = useManagerScheduleData(
193	    selectedLicencee,
194	    locations,
195	    collectorHook.collectors
196	  );
197	  const v2Hook = useCollectionReportV2Data(selectedLicencee, locations);
198	  v2SessionsRef.current = v2Hook.sessions;
199	
200	  // ============================================================================
201	  // Role-Based Visibility Computations
202	  // ============================================================================
203	
204	  const userRoles = (user?.roles || []) as UserRole[];
205	  const canSeeManagerTabs = hasManagerAccess(userRoles);
206	  const isDeveloper = userRoles.includes('developer');
207	  const canManageV2 = isDeveloper || userRoles.includes('admin');
208	
209	  const visibleTabs = COLLECTION_TABS_CONFIG.filter(tab => {
210	    if (tab.id === 'monthly' || tab.id === 'manager') return canSeeManagerTabs;
211	    if (tab.id === 'collection-v2') return isDeveloper;
212	    return true;
213	  });
214	
215	  // Role-based active tab fallback
216	  const effectiveTab =
217	    (activeTab === 'monthly' || activeTab === 'manager') && !canSeeManagerTabs
218	      ? ('collection' as const)
219	      : activeTab === 'collection-v2' && !isDeveloper
220	        ? ('collection' as const)
221	        : activeTab;
222	
223	  // Wrapped refresh that calls correct hook based on active tab
224	  const handleRefreshAll = () => {
225	    if (effectiveTab === 'collection') {
226	      handleRefresh();
227	    } else if (effectiveTab === 'collection-v2') {
228	      v2Hook.onRefresh();
229	    } else if (effectiveTab === 'monthly') {
230	      monthlyHook.onApplyDateRange();
231	    } else if (effectiveTab === 'collector') {
232	      collectorHook.onRefresh();
233	    } else if (effectiveTab === 'manager') {
234	      managerHook.onRefresh();
235	    }
236	  };
237	
238	  const activeRefreshing =
239	    effectiveTab === 'collection'
240	      ? refreshing
241	      : effectiveTab === 'collection-v2'
242	        ? v2Hook.isRefreshing
243	        : effectiveTab === 'monthly'
244	          ? monthlyHook.monthlyLoading
245	          : effectiveTab === 'collector'
246	            ? collectorHook.loadingCollectorSchedules
247	            : effectiveTab === 'manager'
248	              ? managerHook.loadingSchedulers
249	              : false;
250	
251	  // ============================================================================
252	  // Render
253	  // ============================================================================
254	  if (shouldShowNoLicenceeMessage(user)) {
255	    return (
256	      <PageLayout
257	        headerProps={{ setSelectedLicencee }}
258	        pageTitle="Collection Reports"
259	        hideOptions
260	        hideLicenceeFilter
261	        hideCurrencyFilter
262	        mainClassName="flex flex-col flex-1 p-4 md:p-6"
263	        showToaster
264	      >
265	        <NoLicenceeAssigned />
266	      </PageLayout>
267	    );
268	  }
269	
270	  return (
271	    <>
272	      <PageLayout
273	        headerProps={{ setSelectedLicencee, disabled: false }}
274	        hideLicenceeFilter={!shouldShowLicenceeFilter(user)}
275	        hideCurrencyFilter
276	        mainClassName="flex flex-col flex-1 w-full max-w-full p-4 md:p-6 overflow-x-hidden"
277	        showToaster
278	        onRefresh={handleRefreshAll}
279	        refreshing={activeRefreshing}
280	      >
281	        {/* Header Section */}
282	        <CollectionReportHeader
283	          activeTab={effectiveTab}
284	          refreshing={activeRefreshing}
285	          onRefresh={handleRefreshAll}
286	          onCreateDesktop={() => {
287	            if (effectiveTab === 'collection-v2') {
288	              setShowV2StartSession(true);
289	            } else {
290	              handleCreate();
291	            }
292	          }}
293	          onCreateMobile={() => {
294	            if (effectiveTab === 'collection-v2') {
295	              setShowV2StartSession(true);
296	            } else {
297	              handleCreate();
298	            }
299	          }}
300	        />
301	
302	        {/* Navigation Section */}
303	        <div className="mb-4 mt-4">
304	          <CollectionReportNavigation
305	            tabs={visibleTabs}
306	            activeView={effectiveTab}
307	            onChange={handleTabChange}
308	            isLoading={false}
309	          />
310	        </div>
311	
312	        {/* Global Filters Section */}
313	        {(effectiveTab === 'collection' ||
314	          effectiveTab === 'collection-v2') && (
315	          <div className="mb-2 flex flex-col gap-y-4">
316	            <DateFilters hideAllTime={false} customRangeGoLabel="Get Reports" />
317	            {effectiveTab === 'collection-v2' && (
318	              <CollectionReportV2Filters
319	                search={v2Hook.searchTerm}
320	                onSearchChange={v2Hook.setSearchTerm}
321	                searchType={v2Hook.searchType}
322	                onSearchTypeChange={v2Hook.setSearchType}
323	                locations={locations}
324	                selectedLocation={filters.selectedLocation}
325	                onLocationChange={filters.setSelectedLocation}
326	                onClearFilters={filters.clearFilters}
327	              />
328	            )}
329	          </div>
330	        )}
331	
332	        {/* Main Tab Content Section */}
333	        <div className="mt-0 flex-1 overflow-x-hidden overflow-y-visible">
334	          <AnimatePresence mode="wait">
335	            <MotionDiv
336	              key={effectiveTab}
337	              initial={{ opacity: 0, x: 20 }}
338	              animate={{ opacity: 1, x: 0 }}
339	              exit={{ opacity: 0, x: -20 }}
340	              transition={{ duration: 0.2 }}
341	              className="h-full"
342	            >
343	              {/* === COLLECTION TAB === */}
344	              {effectiveTab === 'collection' && (
345	                <div className="tab-content-wrapper">
346	                  <div className="hidden md:block">
347	                    <CollectionReportDesktopLayout
348	                      loading={loading}
349	                      filteredReports={hook.paginatedReports || []}
350	                      desktopTableRef={desktopTableRef}
351	                      locations={locations}
352	                      selectedLocation={filters.selectedLocation}
353	                      onLocationChange={filters.setSelectedLocation}
354	                      search={hook.searchTerm}
355	                      onSearchChange={(value: string) => {
356	                        setSearchTerm(value);
357	                        setIsSearching(value.length > 0);
358	                      }}
359	                      searchType={hook.searchType}
360	                      onSearchTypeChange={hook.setSearchType}
361	                      onSearchSubmit={() => {}}
362	                      showUncollectedOnly={filters.showUncollectedOnly}
363	                      onShowUncollectedOnlyChange={
364	                        filters.setShowUncollectedOnly
365	                      }
366	                      selectedFilters={filters.selectedFilters}
367	                      onFilterChange={filters.handleFilterChange}
368	                      onClearFilters={filters.clearFilters}
369	                      isSearching={isSearching}
370	                      reportIssues={undefined}
371	                      onEdit={handleEdit}
372	                      onDelete={handleDelete}
373	                      sortField={filters.sortField}
374	                      sortDirection={filters.sortDirection}
375	                      onSort={filters.handleSort}
376	                      selectedLicencee={selectedLicencee}
377	                      editableReportIds={hook.editableReportIds}
378	                    />
379	                  </div>
380	
381	                  <div className="md:hidden">
382	                    <CollectionReportMobileLayout
383	                      loading={loading}
384	                      filteredReports={hook.paginatedReports || []}
385	                      mobileCardsRef={mobileCardsRef}
386	                      reportIssues={undefined}
387	                      locations={locations}
388	                      selectedLocation={filters.selectedLocation}
389	                      onLocationChange={filters.setSelectedLocation}
390	                      search={hook.searchTerm}
391	                      onSearchChange={value => {
392	                        setSearchTerm(value);
393	                        setIsSearching(value.length > 0);
394	                      }}
395	                      searchType={hook.searchType}
396	                      onSearchTypeChange={hook.setSearchType}
397	                      onSearchSubmit={() => {}}
398	                      showUncollectedOnly={filters.showUncollectedOnly}
399	                      onShowUncollectedOnlyChange={
400	                        filters.setShowUncollectedOnly
401	                      }
402	                      selectedFilters={filters.selectedFilters}
403	                      onFilterChange={filters.handleFilterChange}
404	                      onClearFilters={filters.clearFilters}
405	                      isSearching={isSearching}
406	                      onEdit={handleEdit}
407	                      onDelete={handleDelete}
408	                      selectedLicencee={selectedLicencee}
409	                      editableReportIds={hook.editableReportIds}
410	                    />
411	                  </div>
412	
413	                  {/* Pagination Section */}
414	                  {(hook.paginatedReports?.length > 0 ||
415	                    filters.filteredReports.length > 0) && (
416	                    <div className="mb-8 mt-4 flex w-full justify-center">
417	                      <PaginationControls
418	                        currentPage={hook.currentPage}
419	                        totalPages={hook.totalPages || 1}
420	                        totalCount={
421	                          filters.selectedLocation !== 'all' ||
422	                          filters.showUncollectedOnly ||
423	                          filters.selectedFilters.length > 0
424	                            ? filters.filteredReports.length
425	                            : hook.totalReports
426	                        }
427	                        setCurrentPage={setCurrentPage}
428	                      />
429	                    </div>
430	                  )}
431	                </div>
432	              )}
433	
434	              {/* === MONTHLY TAB === */}
435	              {effectiveTab === 'monthly' && (
436	                <div className="tab-content-wrapper">
437	                  <MonthlyDesktop {...monthlyHook} />
438	                  <div className="lg:hidden">
439	                    <MonthlyMobile {...monthlyHook} />
440	                  </div>
441	                </div>
442	              )}
443	
444	              {/* === COLLECTOR TAB === */}
445	              {effectiveTab === 'collector' && (
446	                <div className="tab-content-wrapper">
447	                  <CollectorDesktop
448	                    {...collectorHook}
449	                    onEdit={collectorHook.onEdit}
450	                    onDelete={collectorHook.onDelete}
451	                    showActions={collectorHook.canManage}
452	                  />
453	                  <div className="lg:hidden">
454	                    <CollectorMobile
455	                      {...collectorHook}
456	                      onEdit={collectorHook.onEdit}
457	                      onDelete={collectorHook.onDelete}
458	                      showActions={collectorHook.canManage}
459	                    />
460	                  </div>
461	
462	                  {collectorHook.collectorSchedules.length > 0 && (
463	                    <div className="mt-6 flex justify-center">
464	                      <PaginationControls
465	                        currentPage={collectorHook.currentPage}
466	                        totalPages={collectorHook.totalPages}
467	                        setCurrentPage={collectorHook.setCurrentPage}
468	                      />
469	                    </div>
470	                  )}
471	                </div>
472	              )}
473	
474	              {/* === MANAGER TAB === */}
475	              {effectiveTab === 'manager' && (
476	                <div className="tab-content-wrapper">
477	                  <ManagerDesktop
478	                    {...managerHook}
479	                    onEdit={managerHook.onEdit}
480	                    onDelete={managerHook.onDelete}
481	                    showActions={managerHook.canManage}
482	                  />
483	                  <div className="lg:hidden">
484	                    <ManagerMobile
485	                      {...managerHook}
486	                      onEdit={managerHook.onEdit}
487	                      onDelete={managerHook.onDelete}
488	                      showActions={managerHook.canManage}
489	                    />
490	                  </div>
491	
492	                  {managerHook.schedulers.length > 0 && (
493	                    <div className="mt-6 flex justify-center">
494	                      <PaginationControls
495	                        currentPage={managerHook.currentPage}
496	                        totalPages={managerHook.totalPages}
497	                        setCurrentPage={managerHook.setCurrentPage}
498	                      />
499	                    </div>
500	                  )}
501	                </div>
502	              )}
503	
504	              {/* === COLLECTION REPORT V2 TAB (Developer only) === */}
505	              {effectiveTab === 'collection-v2' && (
506	                <div className="tab-content-wrapper">
507	                  <div className="hidden md:block">
508	                    <CollectionReportV2Desktop
509	                      sessions={v2Hook.sessions}
510	                      loading={v2Hook.loading}
511	                      isRefreshing={v2Hook.isRefreshing}
512	                      canManage={canManageV2}
513	                      onViewSession={sessionId => openV2View(sessionId)}
514	                      onEditSession={sessionId =>
515	                        setV2WizardSessionId(sessionId)
516	                      }
517	                      onSubmitSession={async sessionId => {
518	                        try {
519	                          await axios.patch(
520	                            `/api/collection-reports-v2/sessions/${sessionId}/submit`
521	                          );
522	                          v2Hook.onRefresh();
523	                        } catch (error) {
524	                          console.error(
525	                            '[CollectionReportPageContent] Failed to submit session:',
526	                            error instanceof Error
527	                              ? error.message
528	                              : 'Unknown error'
529	                          );
530	                        }
531	                      }}
532	                      onDeleteSession={sessionId => {
533	                        setV2DeleteConfirm(sessionId);
534	                      }}
535	                      sortField={v2Hook.sortField}
536	                      sortDirection={v2Hook.sortDirection}
537	                      onSort={v2Hook.handleSort}
538	                    />
539	                  </div>
540	
541	                  <div className="md:hidden">
542	                    <CollectionReportV2Mobile
543	                      sessions={v2Hook.sessions}
544	                      loading={v2Hook.loading}
545	                      isRefreshing={v2Hook.isRefreshing}
546	                      canManage={canManageV2}
547	                      onViewSession={sessionId => openV2View(sessionId)}
548	                      onEditSession={sessionId =>
549	                        setV2WizardSessionId(sessionId)
550	                      }
551	                      onSubmitSession={async sessionId => {
552	                        try {
553	                          await axios.patch(
554	                            `/api/collection-reports-v2/sessions/${sessionId}/submit`
555	                          );
556	                          v2Hook.onRefresh();
557	                        } catch (error) {
558	                          console.error(
559	                            '[CollectionReportPageContent] Failed to submit session:',
560	                            error instanceof Error
561	                              ? error.message
562	                              : 'Unknown error'
563	                          );
564	                        }
565	                      }}
566	                      onDeleteSession={sessionId => {
567	                        setV2DeleteConfirm(sessionId);
568	                      }}
569	                    />
570	                  </div>
571	
572	                  {v2Hook.sessions.length > 0 && (
573	                    <div className="mb-8 mt-4 flex w-full justify-center">
574	                      <PaginationControls
575	                        currentPage={v2Hook.currentPage}
576	                        totalPages={v2Hook.totalPages}
577	                        setCurrentPage={v2Hook.setCurrentPage}
578	                      />
579	                    </div>
580	                  )}
581	                </div>
582	              )}
583	            </MotionDiv>
584	          </AnimatePresence>
585	        </div>
586	      </PageLayout>
587	
588	      {/* Modal Section: Manager & Collector Dialogs */}
589	      <ScheduleEditModal
590	        open={!!managerHook.editingRow}
591	        onClose={managerHook.onEditClose}
592	        onSave={managerHook.onEditSave}
593	        initialData={
594	          managerHook.editingRow
595	            ? {
596	                collectorName: managerHook.editingRow.collectorName,
597	                locationName: managerHook.editingRow.locationName,
598	                startTime: managerHook.editingRow.rawStartTime,
599	                endTime: managerHook.editingRow.rawEndTime,
600	                status: managerHook.editingRow.status,
601	              }
602	            : null
603	        }
604	        saving={managerHook.saving}
605	      />
606	
607	      <ScheduleDeleteDialog
608	        open={!!managerHook.deletingRow}
609	        onClose={managerHook.onDeleteClose}
610	        onConfirm={managerHook.onDeleteConfirm}
611	        collectorName={managerHook.deletingRow?.collectorName ?? ''}
612	        locationName={managerHook.deletingRow?.locationName ?? ''}
613	        deleting={managerHook.deleting}
614	      />
615	
616	      <ScheduleEditModal
617	        open={!!collectorHook.editingSchedule}
618	        onClose={collectorHook.onEditClose}
619	        onSave={collectorHook.onEditSave}
620	        initialData={
621	          collectorHook.editingSchedule
622	            ? {
623	                collectorName:
624	                  collectorHook.editingSchedule.collectorName ||
625	                  collectorHook.editingSchedule.collector ||
626	                  '',
627	                locationName:
628	                  collectorHook.editingSchedule.locationName ||
629	                  String(collectorHook.editingSchedule.location ?? ''),
630	                startTime: String(collectorHook.editingSchedule.startTime),
631	                endTime: String(collectorHook.editingSchedule.endTime),
632	                status: collectorHook.editingSchedule.status,
633	              }
634	            : null
635	        }
636	        saving={collectorHook.saving}
637	      />
638	
639	      <ScheduleDeleteDialog
640	        open={!!collectorHook.deletingSchedule}
641	        onClose={collectorHook.onDeleteClose}
642	        onConfirm={collectorHook.onDeleteConfirm}
643	        collectorName={
644	          collectorHook.deletingSchedule?.collectorName ||
645	          collectorHook.deletingSchedule?.collector ||
646	          ''
647	        }
648	        locationName={
649	          collectorHook.deletingSchedule?.locationName ||
650	          String(collectorHook.deletingSchedule?.location ?? '')
651	        }
