1	/**
2	 * useCollectionReportFilters Hook
3	 *
4	 * Manages the complex filtering and sorting logic for collection reports.
5	 *
6	 * Architecture:
7	 * - Client-side filtering and sorting
8	 * - Combines location, SMIB, and collection status filters
9	 * - Supports custom date ranges and search relevance
10	 */
11	
12	'use client';
13	
14	// ============================================================================
15	// External Dependencies
16	// ============================================================================
17	
18	import { filterCollectionReports } from '@/lib/helpers/collectionReport';
19	import type { CollectionReportRow } from '@/lib/types/components';
20	import type { LocationSelectItem } from '@/lib/types/location';
21	import type { dateRange as DashboardDateRange } from '@/lib/types';
22	import { useMemo, useState } from 'react';
23	
24	// ============================================================================
25	// Type Definitions
26	// ============================================================================
27	
28	type UseCollectionReportFiltersProps = {
29	  allReports: CollectionReportRow[];
30	  locations: LocationSelectItem[];
31	  searchTerm?: string;
32	  timePeriod?: string;
33	  dateRange?: DashboardDateRange;
34	};
35	
36	// ============================================================================
37	// Main Hook
38	// ============================================================================
39	
40	export function useCollectionReportFilters({
41	  allReports,
42	  locations,
43	  searchTerm = '',
44	  timePeriod = '',
45	  dateRange,
46	}: UseCollectionReportFiltersProps) {
47	  // ==========================================================================
48	  // Local State - Filters
49	  // ==========================================================================
50	  const [selectedLocation, setSelectedLocation] = useState<string | string[]>(
51	    'all'
52	  );
53	  const [showUncollectedOnly, setShowUncollectedOnly] = useState(false);
54	  const [selectedFilters, setSelectedFilters] = useState<string[]>([]);
55	
56	  // ==========================================================================
57	  // Local State - Sorting
58	  // ==========================================================================
59	  const [sortField, setSortField] = useState<keyof CollectionReportRow>('time');
60	  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('desc');
61	
62	  // ==========================================================================
63	  // Computed
64	  // ==========================================================================
65	
66	  /**
67	   * Filtered and sorted collection reports
68	   * - Applies location and collection status filters
69	   * - Applies SMIB-specific filters
70	   * - Sorts by selected field with search relevance
71	   */
72	  const filteredReports = useMemo(() => {
73	    const rdpDateRange = dateRange
74	      ? {
75	          from: dateRange.from || dateRange.startDate || dateRange.start,
76	          to: dateRange.to || dateRange.endDate || dateRange.end,
77	        }
78	      : undefined;
79	
80	    const filtered = filterCollectionReports(
81	      allReports,
82	      selectedLocation,
83	      '',
84	      showUncollectedOnly,
85	      locations,
86	      timePeriod === 'Custom' ? rdpDateRange : undefined
87	    );
88	
89	    let result = filtered;
90	    if (selectedFilters.length > 0) {
91	      result = filtered.filter(report => {
92	        return selectedFilters.some(filter => {
93	          if (filter === 'SMIBLocationsOnly') return !report.noSMIBLocation;
94	          if (filter === 'NoSMIBLocation')
95	            return report.noSMIBLocation === true;
96	          if (filter === 'LocalServersOnly') return report.isLocalServer;
97	          return false;
98	        });
99	      });
100	    }
101	
102	    return [...result].sort((a, b) => {
103	      if (searchTerm.trim()) {
104	        const lowerSearch = searchTerm.trim().toLowerCase();
105	        const aId = String(a.locationReportId || '').toLowerCase();
106	        const bId = String(b.locationReportId || '').toLowerCase();
107	        const aCollector = String(a.collector || '').toLowerCase();
108	        const bCollector = String(b.collector || '').toLowerCase();
109	
110	        const aStarts =
111	          aId.startsWith(lowerSearch) || aCollector.startsWith(lowerSearch);
112	        const bStarts =
113	          bId.startsWith(lowerSearch) || bCollector.startsWith(lowerSearch);
114	
115	        if (aStarts && !bStarts) return -1;
116	        if (!aStarts && bStarts) return 1;
117	      }
118	
119	      const aValue = a[sortField];
120	      const bValue = b[sortField];
121	
122	      if (sortField === 'time') {
123	        const aTime = new Date(aValue as string).getTime();
124	        const bTime = new Date(bValue as string).getTime();
125	        return sortDirection === 'desc' ? bTime - aTime : aTime - bTime;
126	      }
127	
128	      if (typeof aValue === 'number' && typeof bValue === 'number') {
129	        return sortDirection === 'asc' ? aValue - bValue : bValue - aValue;
130	      }
131	
132	      if (typeof aValue === 'string' && typeof bValue === 'string') {
133	        return sortDirection === 'asc'
134	          ? aValue.localeCompare(bValue)
135	          : bValue.localeCompare(aValue);
136	      }
137	
138	      return 0;
139	    });
140	  }, [
141	    allReports,
142	    selectedLocation,
143	    showUncollectedOnly,
144	    locations,
145	    selectedFilters,
146	    sortField,
147	    sortDirection,
148	    searchTerm,
149	    timePeriod,
150	    dateRange,
151	  ]);
152	
153	  // ==========================================================================
154	  // Handlers
155	  // ==========================================================================
156	
157	  /**
158	   * Toggle sort direction or change sort field
159	   */
160	  const handleSort = (field: keyof CollectionReportRow) => {
161	    if (sortField === field) {
162	      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
163	    } else {
164	      setSortField(field);
165	      setSortDirection('desc');
166	    }
167	  };
168	
169	  // ==========================================================================
170	  // Handlers
171	  // ==========================================================================
172	
173	  /**
174	   * Toggle a filter option on/off
175	   */
176	  const handleFilterChange = (filter: string, checked: boolean) => {
177	    if (checked) setSelectedFilters(prev => [...prev, filter]);
178	    else
179	      setSelectedFilters(prev =>
180	        prev.filter(activeFilter => activeFilter !== filter)
181	      );
182	  };
183	
184	  /**
185	   * Reset all filters to defaults
186	   */
187	  const clearFilters = () => {
188	    setSelectedLocation('all');
189	    setShowUncollectedOnly(false);
190	    setSelectedFilters([]);
191	  };
192	
193	  // ==========================================================================
194	  // Return
195	  // ==========================================================================
196	
197	  return {
198	    filteredReports,
199	    selectedLocation,
200	    showUncollectedOnly,
201	    selectedFilters,
202	    sortField,
203	    sortDirection,
204	    setSelectedLocation,
205	    setShowUncollectedOnly,
206	    handleSort,
207	    handleFilterChange,
208	    clearFilters,
209	  };
210	}
