25	import { getAllCollectionReportsWithMachineCounts } from '@/app/api/lib/helpers/collectionReport/service';
26	import {
27	  filterMachinesByChronologicalOrder,
28	  filterReportsByAllowedLocationNames,
29	  handleLocationsWithMachinesRequest,
30	} from '@/app/api/lib/helpers/collectionReport/reportListOperations';
31	import { logCRCreateActivity } from '@/app/api/lib/helpers/collectionReport/crActivityLogger';
32	import { extractUserPermissions } from '@/app/api/lib/helpers/collectionReport/reports';
33	import { connectDB } from '@/app/api/lib/middleware/db';
34	import type { TimePeriod } from '@/app/api/lib/types';
35	import {
36	  logRouteFetch,
37	  logRouteCreate,
38	  logRouteError,
39	  logRoutePhase,
40	  extractUserFromRequest,
41	} from '@/app/api/lib/utils/routeLogger';
42	import type { CreateCollectionReportPayload } from '@/lib/types/api';
