49	/**
50	 * Main GET handler for collection reports
51	 *
52	 * Retrieves collection reports with filtering by time period, licencee, and location;
53	 * also handles sub-queries for locations-with-machines and monthly report summaries.
54	 *
55	 * @param {boolean} locationsWithMachines - If true, returns locations with attached machines instead of reports
56	 * @param {string} timePeriod - Time range preset ('Today', 'Yesterday', '7d', '30d', 'Custom', 'This Month', 'Last Month')
57	 * @param {string} startDate - ISO date string for custom range start
58	 * @param {string} endDate - ISO date string for custom range end
59	 * @param {string} locationName - Filter by specific location name
60	 * @param {string} locationId - Filter by specific location ID
61	 * @param {string} locationIds - Comma-separated list of location IDs to filter by
62	 * @param {string} licencee - Filter by licencee ID or "all"
63	 * @param {number} page - Page number for pagination
64	 * @param {number} limit - Items per page
65	 *
66	 * Flow:
67	 * 1. Connect to the database
68	 * 2. Parse request parameters
69	 * 3. Handle locationsWithMachines sub-query if requested
70	 * 4. Handle monthly report summary sub-query if date range provided without timePeriod
71	 * 5. Calculate date range for time period
72	 * 6. Determine user access and allowed locations
73	 * 7. Parse pagination parameters
74	 * 8. Fetch and filter collection reports
75	 * 9. Return paginated results
76	 */
77	export async function GET(req: NextRequest) {
78	  const startTime = Date.now();
79	  const functionName = 'GET /api/collection-reports';
80	  const user = extractUserFromRequest(req);
81	
82	  try {
83	    // ============================================================================
84	    // STEP 1: Connect to the database
85	    // ============================================================================
86	    await connectDB();
87	
88	    // ============================================================================
89	    // STEP 2: Parse request parameters
90	    // ============================================================================
91	    const { searchParams } = new URL(req.url);
92	
93	    // ============================================================================
94	    // STEP 3: Handle locationsWithMachines query
95	    // ============================================================================
96	    const lwmResult = await handleLocationsWithMachinesRequest(
97	      searchParams,
98	      user,
99	      startTime,
100	      functionName
101	    );
102	    if (lwmResult) {
103	      return lwmResult.response;
104	    }
105	
106	    // ============================================================================
107	    // STEP 4: Handle monthly report summary query
108	    // ============================================================================
109	    const timePeriod =
110	      (searchParams.get('timePeriod') as TimePeriod) || undefined;
111	    const startDateStr = searchParams.get('startDate');
112	    const endDateStr = searchParams.get('endDate');
113	    const locationName = searchParams.get('locationName') || undefined;
114	    const locationId = searchParams.get('locationId') || undefined;
115	    const locationIds =
116	      searchParams.get('locationIds')?.split(',') || undefined;
117	    const rawLicenceeParam = searchParams.get('licencee') || undefined;
118	    const licencee =
119	      rawLicenceeParam && rawLicenceeParam !== 'all'
120	        ? resolveLicenceeId(rawLicenceeParam) || rawLicenceeParam
121	        : rawLicenceeParam;
122	
123	    if (startDateStr && endDateStr && !timePeriod) {
124	      const summary = await getMonthlyCollectionReportSummary(
125	        new Date(startDateStr),
126	        new Date(endDateStr),
127	        locationName || locationIds || (locationId ? [locationId] : undefined),
128	        licencee
129	      );
130	      const details = await getMonthlyCollectionReportByLocation(
131	        new Date(startDateStr),
132	        new Date(endDateStr),
133	        locationName || locationIds || (locationId ? [locationId] : undefined),
134	        licencee
135	      );
136	      // Check for error returns (helpers return '-' or [] on failure)
137	      if (summary.drop === '-' && summary.gross === '-') {
138	        console.warn('[Collection Reports GET] Failed to fetch summary');
139	      }
140	      if (details.length === 0) {
141	        console.warn(
142	          '[Collection Reports GET] No details found for location report'
143	        );
144	      }
145	      const duration = Date.now() - startTime;
146	      logRouteFetch(
147	        functionName,
148	        'GET',
149	        '/api/collection-reports',
150	        details.length,
151	        user,
152	        duration
153	      );
154	      return NextResponse.json({ summary, details });
155	    }
156	
157	    // ============================================================================
158	    // STEP 5: Calculate date range for time period
159	    // ============================================================================
160	    const { startDate, endDate } = calculateDateRangeForTimePeriod(
161	      timePeriod,
162	      startDateStr,
163	      endDateStr
164	    );
165	
166	    // ============================================================================
167	    // STEP 6: Determine user access and allowed locations
168	    // ============================================================================
169	    const userPayload = await getUserFromServer();
170	    if (!userPayload) {
171	      const duration = Date.now() - startTime;
172	      logRouteError(
173	        functionName,
174	        'GET',
175	        '/api/collection-reports',
176	        'Unauthorized',
177	        user
178	      );
179	      console.error(
180	        `[Collection Reports GET API] Unauthorized access after ${duration}ms.`
181	      );
182	      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
183	    }
184	
185	    const userPerms = extractUserPermissions(
186	      userPayload as {
187	        roles?: unknown;
188	        assignedLocations?: string[];
189	        assignedLicencees?: string[];
190	      }
191	    );
192	
193	    const allowedLocationIds = await determineAllowedLocationIds(
194	      userPerms.roles,
195	      userPerms.licencees,
196	      userPerms.locationPermissions
197	    );
198	
199	    if (allowedLocationIds !== 'all' && allowedLocationIds.length === 0) {
200	      return NextResponse.json([]);
201	    }
202	
203	    // ============================================================================
204	    // STEP 7: Parse pagination parameters
205	    // ============================================================================
206	    const page = parseInt(searchParams.get('page') || '1');
207	    const requestedLimit = parseInt(searchParams.get('limit') || '50');
208	    const limit = Math.min(requestedLimit, 100); // Cap at 100 for performance
209	
210	    // ============================================================================
211	    // STEP 8: Fetch and filter collection reports
212	    // ============================================================================
213	    const { searchParams: apiSearchParams } = new URL(req.url);
214	    const search = apiSearchParams.get('search') || undefined;
215	    const searchType = apiSearchParams.get('searchType') || undefined;
216	
217	    const { reports, total } = await getAllCollectionReportsWithMachineCounts(
218	      licencee,
219	      startDate,
220	      endDate,
221	      page,
222	      limit,
223	      userPayload as {
224	        roles?: string[];
225	        moneyInMultiplier?: number | null;
226	        moneyOutAndJackpotMultiplier?: number | null;
227	        reviewerMultiplierStartTime?: Date | string | null;
228	      },
229	      locationIds || (locationId ? [locationId] : undefined),
230	      search,
231	      searchType
232	    );
233	
234	    if (!reports || !Array.isArray(reports)) {
235	      console.error('[Collection Reports GET] Failed to fetch reports');
236	      return NextResponse.json(
237	        { error: 'Failed to fetch reports' },
238	        { status: 500 }
239	      );
240	    }
241	
242	    // Filter reports by allowed locations if needed
243	    // Note: Collection reports store location NAME in the location field, not ID
244	    let paginatedReports = reports;
245	    if (allowedLocationIds !== 'all') {
246	      const { filteredReports, error } =
247	        await filterReportsByAllowedLocationNames(
248	          reports,
