307	/**
308	 * Main POST handler for creating a collection report
309	 *
310	 * Creates a new collection report, syncs machine meter histories, and logs the activity.
311	 *
312	 * @body {string} locationReportId - Unique auto-generated ID for the location report
313	 * @body {string} locationName - Name of the gaming location
314	 * @body {string} collector - Name or user ID of the collector
315	 * @body {number} amountCollected - Total physical cash collected
316	 * @body {number} amountToCollect - Expected amount based on meters
317	 * @body {number} variance - Difference between collected and expected
318	 * @body {number} partnerProfit - Calculated profit split for partner
319	 * @body {number} taxes - Calculated taxes
320	 * @body {Array} machines - Array of machine collection details
321	 *
322	 * Flow:
323	 * 1. Connect to the database
324	 * 2. Parse and validate request body
325	 * 3. Sanitize string fields
326	 * 4. Create collection report using helper
327	 * 5. Log activity
328	 * 6. Return success response
329	 */
330	export async function POST(req: NextRequest) {
331	  const startTime = Date.now();
332	  const functionName = 'POST /api/collection-reports';
333	  const user = extractUserFromRequest(req);
334	
335	  try {
336	    // ============================================================================
337	    // STEP 1: Connect to the database
338	    // ============================================================================
339	    await connectDB();
340	
341	    // ============================================================================
342	    // STEP 2: Parse and validate request body
343	    // ============================================================================
344	    const body = (await req.json()) as CreateCollectionReportPayload;
345	    const validation = validateCollectionReportPayload(body);
346	    if (!validation.isValid) {
347	      const duration = Date.now() - startTime;
348	      console.error(
349	        `[Collection Reports POST API] Validation failed after ${duration}ms: ${validation.error}`
350	      );
351	      return NextResponse.json(
352	        { success: false, error: validation.error },
353	        { status: 400 }
354	      );
355	    }
356	
357	    // ============================================================================
358	    // STEP 3: Sanitize string fields
359	    // ============================================================================
360	    const sanitizedBody = sanitizeCollectionReportPayload(body);
361	
362	    // ============================================================================
363	    // STEP 3.5: Per-Machine Chronological creation check
364	    // ============================================================================
365	    logRoutePhase(functionName, 'chronological check', Date.now() - startTime);
366	    let isInsertingFirstReport = false;
367	    if (
368	      sanitizedBody.location &&
369	      sanitizedBody.timestamp &&
370	      sanitizedBody.machines
371	    ) {
372	      const { validMachines, isInsertingFirstReport: isFirst } =
373	        await filterMachinesByChronologicalOrder(
374	          sanitizedBody.machines,
375	          new Date(sanitizedBody.timestamp)
376	        );
377	
378	      if (validMachines.length === 0) {
379	        return NextResponse.json(
380	          {
381	            success: false,
382	            error:
383	              'All machines were blocked due to chronological constraints (middle-date block).',
384	          },
385	          { status: 400 }
386	        );
387	      }
388	
389	      sanitizedBody.machines = validMachines;
390	      isInsertingFirstReport = isFirst;
391	    }
392	
393	    // ============================================================================
394	    // STEP 4–6: Stream SSE phases while creating the report
395	    // Auth, DB, and validation are done above — only the work portion streams.
396	    // ============================================================================
397	    const ipAddress = getClientIP(req) || undefined;
398	    const userAgent = req.headers.get('user-agent') || null;
399	
400	    return createSseResponse(async send => {
401	      send({ type: 'phase', phase: 'validating' });
402	
403	      // Create report — helper emits saving / recalculating / variation / meters
404	      const result = await createCollectionReport(
405	        sanitizedBody,
406	        phase => send({ type: 'phase', phase }),
407	        (phase, done, total, machineName) =>
408	          send({ type: 'progress', phase, done, total, machineName })
409	      );
410	
411	      if (!result.success) {
412	        const duration = Date.now() - startTime;
413	        console.error(
414	          `[Collection Reports POST API] Failed to create report after ${duration}ms: ${result.error}`
415	        );
416	        send({ type: 'error', message: result.error || 'Failed to create collection report' });
417	        return;
418	      }
419	
420	      // Propagate meters if we inserted before the oldest report
421	      if (
422	        isInsertingFirstReport &&
423	        sanitizedBody.machines &&
424	        sanitizedBody.location &&
425	        sanitizedBody.timestamp
426	      ) {
427	        send({ type: 'phase', phase: 'propagating' });
428	        logRoutePhase(functionName, 'updating linked reports — start', Date.now() - startTime);
429	        await Promise.all(
430	          sanitizedBody.machines.map(machine =>
431	            propagateMetersToNextReport(
432	              machine.machineId,
433	              sanitizedBody.location,
434	              new Date(sanitizedBody.timestamp),
435	              machine.metersIn ?? 0,
436	              machine.metersOut ?? 0
437	            )
438	          )
439	        );
440	        logRoutePhase(functionName, 'updating linked reports — done', Date.now() - startTime);
441	      }
442	
443	      // Log activity
444	      send({ type: 'phase', phase: 'activity' });
445	      const currentUser = await getUserFromServer();
446	      if (currentUser && currentUser.emailAddress) {
447	        await logCRCreateActivity({
448	          body,
449	          result,
450	          sanitizedBody,
451	          ipAddress,
452	          userAgent,
453	          currentUser: currentUser as {
454	            _id?: unknown;
455	            id?: unknown;
456	            sub?: unknown;
457	            emailAddress?: unknown;
458	            username?: unknown;
459	            roles?: unknown;
460	          },
461	        });
462	      }
463	
464	      const duration = Date.now() - startTime;
465	      logRouteCreate(
466	        functionName,
467	        'POST',
468	        '/api/collection-reports',
469	        1,
470	        user,
471	        duration
472	      );
473	
474	      send({ type: 'done', data: { success: true, report: result.report } });
475	    });
476	  } catch (error: unknown) {
477	    const duration = Date.now() - startTime;
478	    const errorMessage =
479	      error instanceof Error ? error.message : 'Internal server error';
480	    logRouteError(
481	      functionName,
482	      'POST',
483	      '/api/collection-reports',
484	      errorMessage,
485	      user
486	    );
487	    console.error(
488	      `[Collection Reports POST API] Error after ${duration}ms:`,
489	      errorMessage
490	    );
491	    return NextResponse.json(
492	      {
493	        success: false,
494	        error: 'Failed to create collection report',
495	        details: errorMessage,
496	      },
497	      { status: 500 }
498	    );
499	  }
500	}
