1	/**
2	 * Collection Report Service Helper Functions
3	 *
4	 * Provides backend helper functions for fetching and enriching collection reports
5	 * with machine counts, financial metrics, and collector details. It uses optimized
6	 * aggregation pipelines to batch process data efficiently and includes collector
7	 * information from the users collection.
8	 *
9	 * Features:
10	 * - Fetches all collection reports with licencee and date range filtering.
11	 * - Enriches reports with machine counts (collected vs total machines).
12	 * - Calculates financial metrics from actual collections (gross, SAS gross, variation).
13	 * - Includes collector details (username, profile information) via lookup.
14	 * - Uses batch aggregation queries for optimal performance.
15	 * - Formats numbers with smart decimal handling.
16	 */
17	
18	import { CollectionReport } from '@/app/api/lib/models/collectionReport';
19	import { Collections } from '@/app/api/lib/models/collections';
20	import { Machine } from '@/app/api/lib/models/machines';
