28	/**
29	 * Formats a number with smart decimal handling
30	 */
31	const formatSmartDecimal = (value: number): string => {
32	  if (isNaN(value)) return '0';
33	  const absValue = Math.abs(value);
34	  const hasDecimals = absValue % 1 !== 0;
35	  const decimalPart = absValue % 1;
36	  const hasSignificantDecimals = hasDecimals && decimalPart >= 0.01;
37	  return value.toFixed(hasSignificantDecimals ? 2 : 0);
38	};
