40	/**
41	 * Backend-only function to fetch all collection reports with machine counts
42	 * This includes the total machine count per location which requires database access
43	 */
44	export async function getAllCollectionReportsWithMachineCounts(
45	  licenceeId?: string,
46	  startDate?: Date,
47	  endDate?: Date,
48	  page = 1,
49	  limit = 50,
50	  reviewerScaleUser?: {
51	    roles?: string[];
52	    moneyInMultiplier?: number | null;
53	    moneyOutAndJackpotMultiplier?: number | null;
54	    reviewerMultiplierStartTime?: Date | string | null;
55	  } | null,
56	  locationIds?: string[],
57	  search?: string,
58	  searchType?: string
59	): Promise<{ reports: CollectionReportRow[]; total: number }> {
60	  let rawReports: Array<Record<string, unknown>> = [];
61	
62	  // Build match criteria
63	  const matchCriteria: Record<string, unknown> = {};
64	
65	  // Apply deletedAt filter - only show active reports (filter out archived)
66	  matchCriteria.$or = [
67	    { deletedAt: null },
68	    { deletedAt: { $exists: false } },
69	    { deletedAt: { $lt: new Date('2025-01-01') } },
70	  ];
71	
72	  // Add date range filtering if provided
73	  if (startDate && endDate) {
74	    matchCriteria.timestamp = { $gte: startDate, $lte: endDate };
75	  }
76	
77	  // Add location filtering if provided
78	  if (locationIds && locationIds.length > 0) {
79	    matchCriteria.location = { $in: locationIds };
80	  }
81	  // Add search filter for fields available before the lookup stage
82	  if (search && searchType) {
83	    if (searchType === 'locationReportId') {
84	      matchCriteria.$or = [
85	        { locationReportId: { $regex: search, $options: 'i' } },
86	        { _id: { $regex: search, $options: 'i' } },
87	      ];
88	    } else if (searchType === 'collectorId') {
89	      matchCriteria.collector = { $regex: search, $options: 'i' };
90	    } else if (searchType === 'locationId') {
91	      matchCriteria.$or = [
92	        { location: { $regex: search, $options: 'i' } },
93	        { locationReportId: { $regex: search, $options: 'i' } },
94	      ];
95	    } else if (searchType === 'location') {
96	      // locationName is a required denormalized field — filter before lookup
97	      matchCriteria.locationName = { $regex: search, $options: 'i' };
98	    }
99	    // 'collector' type is filtered post-lookup against collectorDetails fields below
100	  }
101	  // Always use aggregation to include collector details lookup
102	  const aggregationPipeline: PipelineStage[] = [
103	    {
104	      $match: matchCriteria,
105	    },
106	    {
107	      $lookup: {
108	        from: 'gaminglocations',
109	        localField: 'location',
110	        foreignField: '_id',
111	        as: 'locationDetails',
112	      },
113	    },
114	    {
115	      $unwind: {
116	        path: '$locationDetails',
117	        preserveNullAndEmptyArrays: true,
118	      },
119	    },
120	    // Lookup collector details from users collection
121	    {
122	      $lookup: {
123	        from: 'users',
124	        let: { collectorId: '$collector' },
125	        pipeline: [
126	          { $match: { $expr: { $eq: ['$_id', '$$collectorId'] } } },
127	          { $project: { username: 1, emailAddress: 1, profile: 1 } },
128	        ],
129	        as: 'collectorDetails',
130	      },
131	    },
132	    {
133	      $unwind: {
134	        path: '$collectorDetails',
135	        preserveNullAndEmptyArrays: true,
136	      },
137	    },
138	    // Post-lookup filter for collector name (searches joined user fields)
139	    ...(search && searchType === 'collector'
140	      ? [
141	          {
142	            $match: {
143	              $or: [
144	                {
145	                  'collectorDetails.username': {
146	                    $regex: search,
147	                    $options: 'i',
148	                  },
149	                },
150	                {
151	                  'collectorDetails.profile.firstName': {
152	                    $regex: search,
153	                    $options: 'i',
154	                  },
155	                },
156	                {
157	                  'collectorDetails.profile.lastName': {
158	                    $regex: search,
159	                    $options: 'i',
160	                  },
161	                },
162	                {
163	                  'collectorDetails.emailAddress': {
164	                    $regex: search,
165	                    $options: 'i',
166	                  },
167	                },
168	              ],
169	            },
170	          } as PipelineStage,
171	        ]
172	      : []),
173	    // Apply licencee filter only if provided
174	    ...(licenceeId
175	      ? [
176	          {
177	            $match: {
178	              $or: [
179	                { 'locationDetails.rel.licencee': licenceeId },
180	                { 'locationDetails.rel.licencee': licenceeId },
181	              ],
182	            },
183	          },
184	        ]
185	      : []),
186	    { $sort: { timestamp: -1 } },
187	  ];
188	
189	  // Get total count separately (efficient — no skip/limit on count query)
190	  const countPipeline: PipelineStage[] = [
191	    ...aggregationPipeline,
192	    { $count: 'total' },
193	  ];
194	  const [countResult] = await CollectionReport.aggregate(countPipeline);
195	  const total: number = countResult?.total ?? 0;
196	
197	  // Apply pagination inside the pipeline so Meters queries only run for this page
198	  const skip = (page - 1) * limit;
199	  aggregationPipeline.push({ $skip: skip }, { $limit: limit });
200	
201	  rawReports = await CollectionReport.aggregate(aggregationPipeline);
202	
203	  // PERFORMANCE OPTIMIZATION: Use aggregation to get all data in fewer queries
204	  // Instead of N+1 queries, we'll use aggregation pipelines to get machine counts and collection data
205	
206	  // Get all locationReportIds for batch processing
207	  const locationReportIds = rawReports
208	    .map(doc => doc.locationReportId)
209	    .filter(Boolean);
210	
211	  // Get all unique location IDs for batch machine counting
212	  const uniqueLocationIds = [
213	    ...new Set(
214	      rawReports
215	        .map(doc => {
216	          let locationId = doc.location;
217	          if (typeof locationId === 'object' && locationId !== null) {
218	            if ('_id' in locationId)
219	              locationId = (locationId as { _id: string })._id;
220	            else if ('id' in locationId)
221	              locationId = (locationId as { id: string }).id;
222	          }
223	          if (
224	            !locationId &&
225	            doc.locationDetails &&
226	            typeof doc.locationDetails === 'object'
227	          ) {
228	            const locationDetails = doc.locationDetails as {
229	              _id?: string;
230	              id?: string;
231	            };
232	            locationId = locationDetails._id || locationDetails.id;
233	          }
234	          return locationId;
235	        })
236	        .filter(Boolean)
237	    ),
238	  ];
239	
240	  // Batch query 1: Get collection counts, gross values, and timeframe for all reports
241	  const collectionAggregation = await Collections.aggregate([
242	    {
243	      $match: {
244	        locationReportId: { $in: locationReportIds },
245	      },
246	    },
247	    {
248	      $group: {
249	        _id: '$locationReportId',
250	        collectedMachines: { $sum: 1 },
251	        timeframeStart: { $min: '$timestamp' },
252	        timeframeEnd: { $max: '$timestamp' },
253	        calculatedGross: {
254	          // Use stored movement.gross (denomination-adjusted) to match the detail page.
255	          // Fall back to raw delta for legacy documents that pre-date the movement.gross field.
256	          $sum: {
257	            $ifNull: [
258	              { $toDouble: '$movement.gross' },
259	              {
260	                $subtract: [
261	                  {
262	                    $subtract: [
263	                      { $toDouble: { $ifNull: ['$metersIn', 0] } },
264	                      { $toDouble: { $ifNull: ['$prevIn', 0] } },
265	                    ],
266	                  },
267	                  {
268	                    $subtract: [
269	                      { $toDouble: { $ifNull: ['$metersOut', 0] } },
270	                      { $toDouble: { $ifNull: ['$prevOut', 0] } },
271	                    ],
272	                  },
273	                ],
274	              },
275	            ],
276	          },
277	        },
278	        calculatedSasGross: {
279	          $sum: { $toDouble: { $ifNull: ['$sasMeters.gross', 0] } },
280	        },
281	      },
282	    },
283	  ]);
284	
285	  // Batch query 2: Get total machine counts for all locations
286	  const machineCounts = await Machine.aggregate([
287	    {
288	      $match: {
289	        gamingLocation: { $in: uniqueLocationIds },
290	        $or: [
291	          { deletedAt: null },
292	          { deletedAt: { $lt: new Date('2025-01-01') } },
293	        ],
294	      },
295	    },
296	    {
297	      $group: {
298	        _id: '$gamingLocation',
299	        totalMachines: { $sum: 1 },
300	      },
301	    },
302	  ]);
303	
304	  // Create lookup maps for O(1) access
305	  const collectionDataMap = new Map(
306	    collectionAggregation.map(item => [item._id, item])
307	  );
308	  const machineCountMap = new Map(
309	    machineCounts.map(item => [item._id, item.totalMachines])
310	  );
311	
312	  // Format a raw timestamp value (Date, string, or {$date}) to locale string.
313	  const formatTs = (
314	    ts: unknown,
315	    opts?: Intl.DateTimeFormatOptions
316	  ): string | undefined => {
317	    if (!ts) return undefined;
318	    let date: Date | null = null;
319	    if (ts instanceof Date) {
320	      date = ts;
321	    } else if (typeof ts === 'string') {
322	      date = new Date(ts);
323	    } else if (
324	      typeof ts === 'object' &&
325	      '$date' in (ts as Record<string, unknown>)
326	    ) {
327	      date = new Date((ts as { $date: string }).$date);
328	    }
329	    if (!date || isNaN(date.getTime())) return undefined;
330	    return date.toLocaleString(
331	      undefined,
332	      opts ?? {
333	        year: 'numeric',
334	        month: 'short',
335	        day: '2-digit',
336	        hour: '2-digit',
337	        minute: '2-digit',
338	        hour12: true,
339	      }
340	    );
341	  };
342	
343	  // Define type for the enriched report from aggregation
344	  type EnrichedCollectionReport = {
345	    _id: string;
346	    locationReportId?: string;
347	    locationName?: string;
348	    location?: string | { _id?: string; id?: string };
349	    createdAt?: Date | string;
350	    locationDetails?: {
351	      _id?: string;
352	      id?: string;
353	      slug?: string;
354	      address?: { street?: string; city?: string };
355	      country?: string;
356	      noSMIBLocation?: boolean;
357	      isLocalServer?: boolean;
358	    };
359	    amountCollected?: number;
360	    partnerProfit?: number;
361	    currentBalance?: number;
362	    amountUncollected?: number | string;
363	    timestamp?: Date | string | { $date: string };
364	    noSMIBLocation?: boolean;
365	    isLocalServer?: boolean;
366	    collectorName?: string;
367	    collector?: string;
368	    collectorDetails?: {
369	      username: string;
370	      profile?: {
371	        firstName?: string;
372	        lastName?: string;
373	      };
374	    };
375	    [key: string]: unknown;
376	  };
377	
378	  const enrichedReports = (
379	    rawReports as unknown as EnrichedCollectionReport[]
380	  ).map(doc => {
381	    const locationReportId = (doc.locationReportId as string) || '';
382	    const locationName = (doc.locationName as string) || '';
383	
384	    // Get collection data from batch query
385	    const collectionData = collectionDataMap.get(locationReportId) || {
386	      collectedMachines: 0,
387	      calculatedGross: 0,
388	      calculatedSasGross: 0,
389	      timeframeStart: undefined as Date | undefined,
390	      timeframeEnd: undefined as Date | undefined,
391	    };
392	
393	    // Get location ID for machine count lookup
394	    let locationId = doc.location;
395	    if (typeof locationId === 'object' && locationId !== null) {
396	      if ('_id' in locationId) locationId = (locationId as { _id: string })._id;
397	      else if ('id' in locationId)
398	        locationId = (locationId as { id: string }).id;
399	    }
400	    if (
401	      !locationId &&
402	      doc.locationDetails &&
403	      typeof doc.locationDetails === 'object'
404	    ) {
405	      const locationDetails = doc.locationDetails as {
406	        _id?: string;
407	        id?: string;
408	      };
409	      locationId = locationDetails._id || locationDetails.id;
410	    }
411	
412	    // Get total machines from batch query
413	    const totalMachines =
414	      machineCountMap.get(locationId as string) ||
415	      collectionData.collectedMachines;
416	
417	    // Use stored values for financial data (not calculated from meters)
418	    // Use SAS gross if available, fallback to machine total gross (matches "Total Machine Gross" in UI)
419	    const storedGross =
420	      (doc.totalSasGross as number) || (doc.totalGross as number);
421	    const calculatedCollected = (doc.amountCollected as number) || 0;
422	    const calculatedLocationRevenue = (doc.partnerProfit as number) || 0;
423	    const calculatedBalance = (doc.currentBalance as number) || 0;
424	    const calculatedUncollected =
425	      typeof doc.amountUncollected === 'number'
426	        ? (doc.amountUncollected as number)
427	        : null;
428	
429	    // Priority: calculatedGross (Machine Delta) -> stored totalGross -> totalSasGross from report -> calculatedSasGross
430	    const displayGross =
431	      collectionData.calculatedGross ||
432	      storedGross ||
433	      collectionData.calculatedSasGross;
434	
435	    // Read pre-computed totalVariation stored on the CollectionReport document.
436	    // Backfill migration ensures all historical docs have this field.
437	    const storedVariation = (doc as Record<string, unknown>).totalVariation;
438	    if (storedVariation === undefined) {
439	      console.warn(
440	        `[service] totalVariation missing for report ${locationReportId}`
441	      );
442	    }
443	    const calculatedVariation =
444	      typeof storedVariation === 'number' ? storedVariation : 0;
445	
446	    // Apply reviewer scales to all financial output values before formatting.
447	    // Money in fields use moneyInScale, money out fields use moneyOutScale.
448	    // For non-reviewers scales === 1, so multiplication is a no-op.
449	    const reportTimestampSource = doc.timestamp;
450	    const scaleReferenceDate =
451	      typeof reportTimestampSource === 'string' ||
452	      reportTimestampSource instanceof Date
453	        ? reportTimestampSource
454	        : typeof reportTimestampSource === 'object' &&
455	            reportTimestampSource !== null &&
456	            '$date' in reportTimestampSource &&
457	            typeof reportTimestampSource.$date === 'string'
458	          ? reportTimestampSource.$date
459	          : null;
460	    const moneyInScale = reviewerScaleUser
461	      ? getMoneyInScale(reviewerScaleUser, scaleReferenceDate)
462	      : 1;
463	    const moneyOutScale = reviewerScaleUser
464	      ? getMoneyOutAndJackpotScale(reviewerScaleUser, scaleReferenceDate)
465	      : 1;
466	    const displayVariation = Math.round(calculatedVariation * moneyInScale * 100) / 100;
467	    const scaledGross = Math.round(displayGross * moneyInScale * 100) / 100;
468	    const scaledCollected = Math.round(calculatedCollected * moneyInScale * 100) / 100;
469	    const scaledLocationRevenue = Math.round(calculatedLocationRevenue * moneyInScale * 100) / 100;
470	    const scaledBalance = Math.round(calculatedBalance * moneyOutScale * 100) / 100;
471	    const scaledUncollected =
472	      calculatedUncollected !== null
473	        ? Math.round(calculatedUncollected * moneyInScale * 100) / 100
474	        : null;
475	
476	    // Determine collector value (user ID) and display name
477	    const collectorUserId = (doc.collector as string) || '';
478	    const collectorDetails = doc.collectorDetails as
479	      | {
480	          username?: string;
481	          profile?: { firstName?: string; lastName?: string };
482	          emailAddress?: string;
483	        }
484	      | undefined;
485	
486	    // Compute display name with priority: username → firstName → emailAddress → collectorName
487	    let collectorDisplayName = '';
488	    let collectorFullName = ''; // For tooltip (firstName + lastName when both available)
489	
490	    if (collectorDetails) {
491	      // Check if we have firstName + lastName for tooltip (regardless of display priority)
492	      if (
493	        collectorDetails.profile?.firstName &&
494	        collectorDetails.profile?.lastName
495	      ) {
496	        collectorFullName = `${collectorDetails.profile.firstName} ${collectorDetails.profile.lastName}`;
497	      }
498	
499	      // Priority 1: username
500	      if (collectorDetails.username) {
501	        collectorDisplayName = collectorDetails.username;
502	      }
503	      // Priority 2: firstName only (for main display)
504	      else if (collectorDetails.profile?.firstName) {
505	        collectorDisplayName = collectorDetails.profile.firstName;
506	      }
507	      // Priority 3: emailAddress
508	      else if (collectorDetails.emailAddress) {
509	        collectorDisplayName = collectorDetails.emailAddress;
510	      }
511	    }
512	
513	    // Priority 4: Fallback to legacy collectorName if no user details found
514	    if (!collectorDisplayName) {
515	      collectorDisplayName = (doc.collectorName as string) || '';
516	    }
517	
518	    // Priority 5: Fallback to 'Deleted User' if user not found and no legacy name is set
519	    if (!collectorDisplayName && collectorUserId) {
520	      if (
521	        /^[0-9a-fA-F]{24}$/.test(collectorUserId) ||
522	        collectorUserId.startsWith('user_') ||
523	        collectorUserId.length > 15
524	      ) {
525	        collectorDisplayName = 'Deleted User';
526	      } else {
527	        collectorDisplayName = collectorUserId;
528	      }
529	    }
530	
531	    // If we have displayName but no fullName set, use displayName as fullName
532	    if (!collectorFullName && collectorDisplayName) {
533	      collectorFullName = collectorDisplayName;
534	    }
535	
536	    const collectorUserNotFound = !collectorDetails && !!collectorUserId;
537	
538	    // Prepare tooltip data: firstName, lastName, ID, email
539	    const collectorTooltipData = collectorDetails
540	      ? {
541	          firstName: collectorDetails.profile?.firstName || undefined,
542	          lastName: collectorDetails.profile?.lastName || undefined,
543	          id: collectorUserId || undefined,
544	          email: collectorDetails.emailAddress || undefined,
545	        }
546	      : collectorUserId
547	        ? {
548	            firstName: undefined,
549	            lastName: undefined,
550	            id: collectorUserId,
551	            email: undefined,
552	          }
553	        : undefined;
554	
555	    const result = {
556	      _id: doc._id || '',
557	      locationReportId,
558	      locationId:
559	        doc.locationDetails?._id ||
560	        (typeof doc.location === 'object' && doc.location !== null
561	          ? doc.location._id
562	          : ''),
563	      locationSlug: doc.locationDetails?.slug || '',
564	      locationTooltipData: {
565	        id: doc.locationDetails?._id || undefined,
566	        address: [
567	          doc.locationDetails?.address?.street,
568	          doc.locationDetails?.address?.city,
569	        ]
570	          .filter(Boolean)
571	          .join(', ') || undefined,
572	        country: doc.locationDetails?.country || undefined,
573	        noSMIBLocation: doc.locationDetails?.noSMIBLocation || false,
574	        isLocalServer: doc.locationDetails?.isLocalServer || false,
575	      },
576	      collector: collectorUserId, // User ID (primary field)
577	      collectorFullName: collectorDisplayName || undefined, // Display name (username → firstName → email → collectorName)
578	      collectorFullNameTooltip: collectorFullName || undefined, // Full name for tooltip (firstName + lastName when available)
579	      collectorTooltipData, // Tooltip data with firstName, lastName, ID, email
580	      collectorUserNotFound, // Flag to indicate user no longer exists
581	      location: locationName,
582	      gross: formatSmartDecimal(scaledGross),
583	      machines: `${collectionData.collectedMachines || 0}/${totalMachines || 0}`,
584	      collected: formatSmartDecimal(scaledCollected),
585	      uncollected:
586	        scaledUncollected !== null
587	          ? formatSmartDecimal(scaledUncollected)
588	          : (doc.amountUncollected as string) || '-',
589	      variation: formatSmartDecimal(displayVariation),
590	      balance: formatSmartDecimal(scaledBalance),
591	      locationRevenue: formatSmartDecimal(scaledLocationRevenue),
592	      time: (() => {
593	        const ts = doc.timestamp;
594	        if (ts) {
595	          const date =
596	            typeof ts === 'string' || ts instanceof Date
597	              ? new Date(ts)
598	              : typeof ts === 'object' &&
599	                  '$date' in ts &&
600	                  typeof ts.$date === 'string'
601	                ? new Date(ts.$date)
602	                : null;
603	
604	          if (date) {
605	            // Format in local time (not UTC)
606	            return date.toLocaleString(undefined, {
607	              year: 'numeric',
608	              month: 'short',
609	              day: '2-digit',
610	              hour: '2-digit',
611	              minute: '2-digit',
612	              second: '2-digit',
613	              hour12: true,
614	            });
615	          }
616	        }
617	        return '-';
618	      })(),
619	      createdAt: formatTs(doc.createdAt),
620	      timeframeStart: formatTs(collectionData.timeframeStart, {
621	        month: 'short',
622	        day: '2-digit',
623	        hour: '2-digit',
624	        minute: '2-digit',
625	        hour12: true,
626	      }),
627	      timeframeEnd: formatTs(collectionData.timeframeEnd, {
628	        month: 'short',
629	        day: '2-digit',
630	        hour: '2-digit',
631	        minute: '2-digit',
632	        hour12: true,
633	      }),
634	      noSMIBLocation: (doc.noSMIBLocation as boolean) || false,
635	      isLocalServer: (doc.isLocalServer as boolean) || false,
636	      deletedAt: (doc.deletedAt as string | null) || null,
637	    };
638	
639	    return result;
640	  });
641	
642	  return { reports: enrichedReports, total };
643	}
