35	/**
36	 * Validates machine collections for chronological ordering.
37	 * Skips machines that have BOTH a previous and next collection (middle-date insert).
38	 * Returns filtered valid machines and a flag indicating if this is the first report.
39	 */
40	export async function filterMachinesByChronologicalOrder(
41	  machines: CreateCollectionReportPayload['machines'],
42	  targetTime: Date
43	): Promise<{
44	  validMachines: NonNullable<CreateCollectionReportPayload['machines']>;
45	  isInsertingFirstReport: boolean;
46	}> {
47	  if (!machines || !Array.isArray(machines)) {
48	    return { validMachines: [], isInsertingFirstReport: false };
49	  }
50	
51	  const validMachines: NonNullable<CreateCollectionReportPayload['machines']> =
52	    [];
53	  let firstReportInsertedCount = 0;
54	
55	  for (const machine of machines) {
56	    if (!machine.machineId) continue;
57	
58	    const nextReport = await Collections.findOne({
59	      machineId: machine.machineId,
60	      timestamp: { $gt: targetTime },
61	      deletedAt: { $exists: false },
62	    }).lean<CollectionDocument>();
63	
64	    const prevReport = await Collections.findOne({
65	      machineId: machine.machineId,
66	      timestamp: { $lt: targetTime },
67	      deletedAt: { $exists: false },
68	    }).lean<CollectionDocument>();
69	
70	    if (nextReport && prevReport) {
71	      console.warn(
72	        `[filterMachinesByChronologicalOrder] Chronological check failed for machine ${machine.machineId}: cannot insert a middle-date collection.`
73	      );
74	      continue;
75	    }
76	
77	    validMachines.push(machine);
78	
79	    if (nextReport && !prevReport) {
80	      firstReportInsertedCount++;
81	    }
82	  }
83	
84	  return {
85	    validMachines,
86	    isInsertingFirstReport: firstReportInsertedCount > 0,
87	  };
88	}
