90	/**
91	 * Filters collection reports by allowed location names.
92	 * Collection reports store location NAME in the location field, not ID.
93	 */
94	export async function filterReportsByAllowedLocationNames(
95	  reports: CollectionReportRow[],
96	  allowedLocationIds: string[]
97	): Promise<{ filteredReports: CollectionReportRow[]; error?: string }> {
98	  if (!Array.isArray(reports)) {
99	    return { filteredReports: [] };
100	  }
101	
102	  const locations = await GamingLocations.find(
103	    { _id: { $in: allowedLocationIds } },
104	    { _id: 1, name: 1 }
105	  )
106	    .lean<GamingLocationDocument[]>()
107	    .exec();
108	
109	  const allowedLocationNames = locations.map(loc => String(loc.name));
110	
111	  if (!Array.isArray(allowedLocationNames)) {
112	    console.error(
113	      '[filterReportsByAllowedLocationNames] Failed to fetch location names'
114	    );
115	    return { filteredReports: [], error: 'Failed to fetch location names' };
116	  }
117	
118	  const filteredReports = reports.filter(report => {
119	    const reportLocationName = String(report.location);
120	    return allowedLocationNames.includes(reportLocationName);
121	  });
122	
123	  return { filteredReports };
124	}
