215	  const locationId = searchParams.get('locationId') || undefined;
216	  const locationIds =
217	    searchParams.get('locationIds')?.split(',') || undefined;
218	  const rawLicenceeParam = searchParams.get('licencee') || undefined;
219	  const licencee =
220	    rawLicenceeParam && rawLicenceeParam !== 'all'
221	      ? resolveLicenceeId(rawLicenceeParam) || rawLicenceeParam
222	      : rawLicenceeParam;
223	
224	  const summary = await getMonthlyCollectionReportSummary(
225	    new Date(startDateStr),
226	    new Date(endDateStr),
227	    locationName || locationIds || (locationId ? [locationId] : undefined),
228	    licencee
229	  );
230	  const details = await getMonthlyCollectionReportByLocation(
231	    new Date(startDateStr),
232	    new Date(endDateStr),
233	    locationName || locationIds || (locationId ? [locationId] : undefined),
234	    licencee
235	  );
236	
237	  if (summary.drop === '-' && summary.gross === '-') {
238	    console.warn('[Collection Reports GET] Failed to fetch summary');
