245	
246	  const duration = Date.now() - startTime;
247	  logRouteFetch(
248	    functionName,
249	    'GET',
250	    '/api/collection-reports',
251	    details.length,
252	    user ?? undefined,
253	    duration
254	  );
255	
256	  return { response: NextResponse.json({ summary, details }) };
257	}
