27	/**
28	 * Main GET handler for fetching collection report locations
29	 *
30	 * Returns locations accessible to the authenticated user, filtered by licencee,
31	 * for use in collection report forms and filters.
32	 *
33	 * @param {NextRequest} req - Information about the incoming request
34	 * @param {string} licencee - Optional query param. Licencee ID or slug to scope results.
35	 *
36	 * Flow:
37	 * 1. Connect to the database
38	 * 2. Parse query parameters
39	 * 3. Get user's accessible licencees and permissions
40	 * 4. Build query filter based on access control and deletion status
41	 * 5. Fetch locations with minimal projection
42	 * 6. Return locations array with id and name
43	 */
44	export async function GET(req: NextRequest) {
45	  const startTime = Date.now();
46	  const functionName = 'GET /api/collection-reports/locations';
47	  const user = extractUserFromRequest(req);
48	
49	  try {
50	    // ============================================================================
51	    // STEP 1: Connect to the database
52	    // ============================================================================
53	    await connectDB();
54	
55	    // ============================================================================
56	    // STEP 2: Parse query parameters
57	    // ============================================================================
58	    const { searchParams } = new URL(req.url);
59	    // Support both 'licencee' and 'licencee' spelling
60	    const rawLicenceeParam = searchParams.get('licencee');
61	    const licencee =
62	      rawLicenceeParam && rawLicenceeParam !== 'all'
63	        ? resolveLicenceeId(rawLicenceeParam) || rawLicenceeParam
64	        : rawLicenceeParam;
65	
66	    // ============================================================================
67	    // STEP 3: Get user's accessible licencees and permissions
68	    // ============================================================================
69	    const userAccessibleLicencees = await getUserAccessibleLicenceesFromToken();
70	    const userPayload = await getUserFromServer();
71	    if (!userPayload) {
72	      logRouteError(
73	        functionName,
74	        'GET',
75	        '/api/collection-reports/locations',
76	        'Unauthorized',
77	        user
78	      );
79	      return NextResponse.json({ locations: [] }, { status: 401 });
80	    }
81	
82	    const userRoles = (userPayload?.roles as string[]) || [];
83	    // Use only new field
84	    let userLocationPermissions: string[] = [];
85	    if (
86	      Array.isArray(
87	        (userPayload as { assignedLocations?: string[] })?.assignedLocations
88	      )
89	    ) {
90	      userLocationPermissions = (userPayload as { assignedLocations: string[] })
91	        .assignedLocations;
92	    }
93	
94	    // ============================================================================
95	    // STEP 4: Build query filter based on access control
96	    // ============================================================================
97	    const deletionFilter = {
98	      $or: [
99	        { deletedAt: null },
100	        { deletedAt: { $lt: new Date('2025-01-01') } },
101	      ],
102	    };
103	
104	    const allowedLocationIds = await getUserLocationFilter(
105	      userAccessibleLicencees,
106	      licencee || undefined,
107	      userLocationPermissions,
108	      userRoles
109	    );
110	
111	    let queryFilter: Record<string, unknown>;
112	    if (allowedLocationIds !== 'all') {
113	      if (allowedLocationIds.length === 0) {
114	        // No accessible locations
115	        queryFilter = { ...deletionFilter, _id: null };
116	      } else {
117	        queryFilter = { ...deletionFilter, _id: { $in: allowedLocationIds } };
118	      }
119	    } else {
120	      queryFilter = deletionFilter;
121	    }
122	
123	    // ============================================================================
124	    // STEP 5: Fetch locations with minimal projection
125	    // ============================================================================
126	    const locations = await GamingLocations.find(queryFilter, {
127	      _id: 1,
128	      name: 1,
129	    })
130	      .sort({ name: 1 })
131	      .lean<GamingLocationDocument[]>();
132	
133	    // ============================================================================
134	    // STEP 6: Return locations with id and name
135	    // ============================================================================
136	    const locationsWithId = locations.map(loc => ({
137	      id: String(loc._id),
138	      name: loc.name,
139	    }));
140	
141	    const duration = Date.now() - startTime;
142	    logRouteFetch(
143	      functionName,
144	      'GET',
145	      '/api/collection-reports/locations',
146	      locationsWithId.length,
147	      user,
148	      duration
149	    );
150	
151	    return NextResponse.json({ locations: locationsWithId });
152	  } catch (error: unknown) {
153	    const duration = Date.now() - startTime;
154	    const errorMessage =
155	      error instanceof Error ? error.message : 'Internal server error';
156	    logRouteError(
157	      functionName,
158	      'GET',
159	      '/api/collection-reports/locations',
160	      errorMessage,
161	      user
162	    );
163	    console.error(
164	      `[Collection Report Locations GET API] Error after ${duration}ms:`,
165	      errorMessage
166	    );
167	    return NextResponse.json({ locations: [] }, { status: 500 });
168	  }
169	}
