61	export async function fetchAllGamingLocations(licencee?: string) {
62	  try {
63	    const locationsList = await getAllGamingLocations(licencee);
64	    if (locationsList && Array.isArray(locationsList)) {
65	      const formattedLocations = locationsList.map(loc => {
66	        const locObj = loc as Record<string, unknown>;
67	        const rel = locObj.rel as Record<string, unknown> | undefined;
68	        return {
69	          id:
70	            (locObj._id as string)?.toString() || (locObj._id as string) || '',
71	          name:
72	            (locObj.name as string) ||
73	            (locObj.locationName as string) ||
74	            'Unknown Location',
75	          slug: (locObj.slug as string) || '',
76	          licenceeId:
77	            (locObj.licenceeId as string) ||
78	            (locObj.licencee as string) ||
79	            (rel?.licencee as string) ||
80	            (rel?.licencee as string) ||
81	            '',
82	          membershipEnabled:
83	            (locObj.membershipEnabled as boolean) === true ||
84	            (locObj.enableMembership as boolean) === true,
85	        };
86	      });
87	      // Sort alphabetically by name as additional safeguard
88	      return formattedLocations.sort((a, b) => a.name.localeCompare(b.name));
